INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-5ff21eeb-moex-00164', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅義務人應納稅捐，於繳納期間屆滿30日後仍未繳納者，由稅捐稽徵機關移送強制執行，下列 何者非暫緩移送強制執行之事由？', '["納稅義務人已繳納復查決定應納稅額三分之一稅款並依法提起訴願", "經稅捐稽徵機關核准，按復查決定應納稅額三分之一提供相當擔保並依法提起訴願", "稅捐稽徵機關就納稅義務人相當於復查決定應納稅額三分之一之土地，通知有關機關不得為移 轉或設定他項權利", "納稅義務人已於法定期間內申請復查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00165', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '稅捐稽徵法關於稅捐刑罰之規定，下列敘述何者正確？', '["納稅義務人以詐術或其他不正當方法逃漏稅捐，個人逃漏稅額在5,000萬元以上、營利事業逃漏稅 額在1億元以上者，處1年以上7年以下有期徒刑，拘役或科或併科1,000萬元以上1億元以下罰款", "納稅義務人逃漏稅捐應處刑罰之規定，於公司法規定之公司負責人適用之，且以登記負責人為準", "代徵人或扣繳義務人侵占已代繳或已扣繳之稅捐者，處5年以下有期徒刑、拘役或科或併科6萬 元以下罰金", "執行業務會計師幫助納稅義務人以詐術或其他不正當方法逃漏稅捐應處刑罰者，加重其刑至三 分之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00166', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依稅法規定逾期繳納稅款者應加徵滯納金之案件，其稅額繳款書之繳納期間末日為112年8月10日 星期四，該日是行政機關照常上班日，納稅義務人於同年8月15日星期二始繳納稅款，請問其滯納 金加徵率為何？', '["免加徵", "1%", "2%", "3%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00167', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列關於納稅者權利保護法之敘述，何者錯誤？', '["納稅者權利保障，包括憲法規定之生存權、工作權、財產權及其他相關基本權利", "關於臺北市地方稅之納稅者權利保護案件，臺北市政府為納稅者權利保護法之主管機關", "地方自治團體依地方稅法通則制定地方稅自治條例據以開徵之地方稅，不適用納稅者權利保護法", "納稅者權利之保護，於納稅者權利保護法有特別規定者，應優先適用該法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00168', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依納稅者權利保護法及稅捐稽徵法之規定，下列何者非屬稅捐主管機關應主動公開之資訊？', '["稅式支出情形", "稅捐事項所作成之解釋函令及行政規則", "納稅者權利保護官之姓名及聯絡之資訊", "納稅額較高之納稅義務人之姓名或名稱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00169', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '有關稅捐徵收期間之規定，下列敘述何者正確？', '["稅捐之徵收期間為5年，自繳納期間屆滿之翌日起算", "徵收期間屆滿前，稅捐稽徵機關已於公司清算期間申報債權者，徵收期間不受5年之限制", "納稅義務人提起行政救濟，並對復查決定應納稅額繳納三分之一，依法提起訴願，其5年徵收期 間之計算，為扣除訴願至行政救濟完結之期間", "5年徵收期間屆滿前已移送執行者，自徵收期間屆滿之翌日起，逾5年未能執行終結者，不得再 執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00170', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列關於納稅者權利保護官（下稱納保官）之敘述，何者錯誤？', '["納保官係由公正人士、學者、專家以任務編組方式擔任", "納稅者提起復查時，納保官可提供必要諮詢與協助", "納保官應提出納稅者權利保護工作成果報告", "納稅者有稅捐爭議，可尋求納保官協助進行溝通及協調"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00171', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅者權利保護法關於租稅規避之規定，下列敘述何者錯誤？', '["租稅規避及課徵租稅構成要件事實之認定，由稅捐稽徵機關負舉證責任", "稅捐稽徵機關對租稅規避案件進行調查，納稅義務人未提示證明文據，其有應補徵稅款者，應 加徵15%滯納金及加計利息，不得處漏稅罰", "租稅規避案件經處漏稅罰者，不得再加徵15%滯納金", "稅捐稽徵機關對租稅規避案件，不得推計課稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00172', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅者權利保護法第4條規定，納稅者為維持基本生活所需之費用，不得加以課稅。計算納稅者綜 合所得稅申報戶之免稅額及扣除額合計數，是否已達該申報戶維持基本生活所需費用總額時，不 列入計算之扣除額項目為那幾項？', '["標準扣除額及薪資所得特別扣除額", "捐贈及薪資所得特別扣除額", "財產交易損失及薪資所得特別扣除額", "災害損失及薪資所得特別扣除額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00173', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅者權利保護法第16條第2項規定：「納稅者不得因不知法規而免除行政處罰責任。但按其情節， 得減輕或免除其處罰。」有關減輕處罰之規定，下列敘述何者正確？', '["依稅捐稽徵法第48條之2之規定，得減輕或免除處罰之標準，授權財政部訂定", "稅務違章案件裁罰金額或倍數參考表變更時，不利於納稅義務人者，自財政部指定之一定期日 起，開始適用", "凡未經檢舉或未經稅捐稽徵機關進行調查前，納稅人自動補報者，可免除逃漏稅之行為罰、漏 稅罰及刑罰", "稅捐稽徵機關為處罰，應審酌納稅者應受責難程度、所生影響、所得之利益及考量納稅者之資 力；於補徵稅額者，亦準用之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
